type AIPingRequestObject struct {
	Body *AIPingJSONRequestBody
}

type AIPingResponseObject interface {
	VisitAIPingResponse(w http.ResponseWriter) error
}

type AIPing200TexteventStreamResponse struct {
	Body          io.Reader
	ContentLength int64
}

func (response AIPing200TexteventStreamResponse) VisitAIPingResponse(w http.ResponseWriter) error {
	w.Header().Set("Content-Type", "text/event-stream")
	if response.ContentLength != 0 {
		w.Header().Set("Content-Length", fmt.Sprint(response.ContentLength))
	}
	w.WriteHeader(200)

	if closer, ok := response.Body.(io.ReadCloser); ok {
		defer closer.Close()
	}
	_, err := io.Copy(w, response.Body)
	return err
}

